import { Component } from '@angular/core';

@Component({
  selector: 'app-about',
  standalone: true,
  template: `
    <section class="page">
      <h1>About Me</h1>
      <p>A short bio, your background, skills, and what drives you.</p>
    </section>
  `
})
export class AboutComponent {}
